INSERT INTO node_properties (id, node_id, name, value_type, string_value, date_value, ref_node_id) VALUES
('d5000000-0003-0000-0000-000000000001', 'd5000000-0001-0000-0000-000000000001', 'description', 'STRING', 'Premier réseau social de l''histoire (1997). Permettait de connecter des profils en ligne et d''envoyer des messages. Fermé en 2001 faute de modèle économique', NULL, NULL),
('d5000000-0003-0000-0000-000000000002', 'd5000000-0001-0000-0000-000000000001', 'annee_lancement', 'STRING', '1997', NULL, NULL),
('d5000000-0003-0000-0000-000000000003', 'd5000000-0001-0000-0000-000000000001', 'fondateur', 'STRING', 'Andrew Weinreich', NULL, NULL),
('d5000000-0003-0000-0000-000000000004', 'd5000000-0001-0000-0000-000000000002', 'description', 'STRING', 'Premier réseau social grand public (2002). A introduit le concept de profil personnel en ligne et les connexions entre amis. Abandonné au profit de Facebook', NULL, NULL),
('d5000000-0003-0000-0000-000000000005', 'd5000000-0001-0000-0000-000000000002', 'annee_lancement', 'STRING', '2002', NULL, NULL),
('d5000000-0003-0000-0000-000000000006', 'd5000000-0001-0000-0000-000000000003', 'description', 'STRING', 'Réseau social dominant de 2003 à 2008. A popularisé la personnalisation des profils et la musique en ligne. Pionnier de l''économie des créateurs avec Tom Anderson', NULL, NULL),
('d5000000-0003-0000-0000-000000000007', 'd5000000-0001-0000-0000-000000000003', 'annee_lancement', 'STRING', '2003', NULL, NULL),
('d5000000-0003-0000-0000-000000000008', 'd5000000-0001-0000-0000-000000000003', 'pic_utilisateurs', 'STRING', '100 millions (2006)', NULL, NULL),
('d5000000-0003-0000-0000-000000000009', 'd5000000-0001-0000-0000-000000000004', 'description', 'STRING', 'Réseau professionnel fondé en 2002. A redéfini le networking professionnel en ligne. Racheté par Microsoft en 2016 pour 26 milliards de dollars', NULL, NULL),
('d5000000-0003-0000-0000-000000000010', 'd5000000-0001-0000-0000-000000000004', 'annee_lancement', 'STRING', '2003', NULL, NULL),
('d5000000-0003-0000-0000-000000000011', 'd5000000-0001-0000-0000-000000000004', 'utilisateurs', 'STRING', '900 millions', NULL, NULL),
('d5000000-0003-0000-0000-000000000012', 'd5000000-0001-0000-0000-000000000005', 'description', 'STRING', 'Fondé par Mark Zuckerberg en 2004 à Harvard. A révolutionné les réseaux sociaux en connectant le monde entier. A acquis Instagram et WhatsApp pour dominer le marché', NULL, NULL),
('d5000000-0003-0000-0000-000000000013', 'd5000000-0001-0000-0000-000000000005', 'annee_lancement', 'STRING', '2004', NULL, NULL),
('d5000000-0003-0000-0000-000000000014', 'd5000000-0001-0000-0000-000000000005', 'utilisateurs', 'STRING', '3 milliards', NULL, NULL),
('d5000000-0003-0000-0000-000000000015', 'd5000000-0001-0000-0000-000000000005', 'fondateur', 'STRING', 'Mark Zuckerberg', NULL, NULL),
('d5000000-0003-0000-0000-000000000016', 'd5000000-0001-0000-0000-000000000006', 'description', 'STRING', 'Plateforme de vidéos fondée en 2005, rachetée par Google en 2006 pour 1,65 milliard. A inventé l''économie des créateurs de contenu vidéo avec plus de 2 milliards d''utilisateurs', NULL, NULL),
('d5000000-0003-0000-0000-000000000017', 'd5000000-0001-0000-0000-000000000006', 'annee_lancement', 'STRING', '2005', NULL, NULL),
('d5000000-0003-0000-0000-000000000018', 'd5000000-0001-0000-0000-000000000006', 'utilisateurs', 'STRING', '2,7 milliards', NULL, NULL),
('d5000000-0003-0000-0000-000000000019', 'd5000000-0001-0000-0000-000000000007', 'description', 'STRING', 'Réseau de microblogging fondé par Jack Dorsey en 2006. A révolutionné la communication en temps réel et l''information instantanée avec le format 140 caractères', NULL, NULL),
('d5000000-0003-0000-0000-000000000020', 'd5000000-0001-0000-0000-000000000007', 'annee_lancement', 'STRING', '2006', NULL, NULL),
('d5000000-0003-0000-0000-000000000021', 'd5000000-0001-0000-0000-000000000007', 'fondateur', 'STRING', 'Jack Dorsey', NULL, NULL),
('d5000000-0003-0000-0000-000000000022', 'd5000000-0001-0000-0000-000000000009', 'description', 'STRING', 'Réseau de partage photo fondé en 2010, racheté par Facebook pour 1 milliard en 2012. A popularisé la culture visuelle et les filtres. Plateforme principale des influenceurs', NULL, NULL),
('d5000000-0003-0000-0000-000000000023', 'd5000000-0001-0000-0000-000000000009', 'annee_lancement', 'STRING', '2010', NULL, NULL),
('d5000000-0003-0000-0000-000000000024', 'd5000000-0001-0000-0000-000000000009', 'utilisateurs', 'STRING', '2 milliards', NULL, NULL),
('d5000000-0003-0000-0000-000000000025', 'd5000000-0001-0000-0000-000000000010', 'description', 'STRING', 'Réseau de photos éphémères fondé en 2011. A inventé le format Stories repris par Instagram, Facebook et TikTok. Pionnier de la communication éphémère', NULL, NULL),
('d5000000-0003-0000-0000-000000000026', 'd5000000-0001-0000-0000-000000000010', 'annee_lancement', 'STRING', '2011', NULL, NULL),
('d5000000-0003-0000-0000-000000000027', 'd5000000-0001-0000-0000-000000000011', 'description', 'STRING', 'Application de vidéos courtes fondée en 2016 par ByteDance en Chine. Phénomène mondial avec 1 milliard d''utilisateurs. A révolutionné la découverte de contenu via l''algorithme', NULL, NULL),
('d5000000-0003-0000-0000-000000000028', 'd5000000-0001-0000-0000-000000000011', 'annee_lancement', 'STRING', '2016', NULL, NULL),
('d5000000-0003-0000-0000-000000000029', 'd5000000-0001-0000-0000-000000000011', 'utilisateurs', 'STRING', '1,5 milliard', NULL, NULL),
('d5000000-0003-0000-0000-000000000030', 'd5000000-0001-0000-0000-000000000011', 'fondateur', 'STRING', 'Zhang Yiming (ByteDance)', NULL, NULL),
('d5000000-0003-0000-0000-000000000031', 'd5000000-0001-0000-0000-000000000013', 'description', 'STRING', 'Alternative à Twitter lancée par Meta en 2023 suite au rachat de Twitter par Elon Musk. A atteint 100 millions d''utilisateurs en 5 jours, record historique', NULL, NULL),
('d5000000-0003-0000-0000-000000000032', 'd5000000-0001-0000-0000-000000000013', 'annee_lancement', 'STRING', '2023', NULL, NULL),
('d5000000-0003-0000-0000-000000000033', 'd5000000-0001-0000-0000-000000000017', 'description', 'STRING', 'Twitter renommé X par Elon Musk en 2023 après son rachat pour 44 milliards. Ambition de devenir une super-app intégrant paiements, vidéo et messagerie', NULL, NULL),
('d5000000-0003-0000-0000-000000000034', 'd5000000-0001-0000-0000-000000000017', 'annee_transformation', 'STRING', '2023', NULL, NULL),
('d5000000-0003-0000-0000-000000000035', 'd5000000-0001-0000-0000-000000000017', 'nouveau_proprietaire', 'STRING', 'Elon Musk', NULL, NULL);
